import type { DialogueEntry } from '../../../types';
import { CharacterId } from '../characters';
import { Portrait } from '../portraits';
import { Background } from '../backgrounds';

export const scene: DialogueEntry[] = [
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "十八點十一分。雨變了。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是變大。是變重。雨點不再是從天上掉下來的水滴，而是被風斜著甩過來的、帶著重量的東西，打在車身上發出悶響。校務車的雨刷已經開到了最快，但每一次刷過之後，擋風玻璃上立刻又被新的雨幕糊滿。透過駕駛座靠背的縫隙，顧言只能看到兩束昏黃的車燈光柱，在雨裡照出不到十公尺的距離，然後被黑暗吃掉。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "後山維修路比他想像的更窄。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "單車道。路面的柏油早就剝落了大半，露出下面的碎石和泥土。左邊是山坡，密密麻麻的樹叢壓過來，枝葉在風裡抽打著車身。右邊——是低矮的護欄。鐵的，鏽跡斑斑，高度只到膝蓋。護欄外面是一個斜坡，斜坡下面是排水溝。溝裡的水已經滿了，渾濁的、帶著泥沙的雨水在溝底翻滾，像一條發怒的蛇，看不見盡頭。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)這條路。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不是主山路。主山路有護欄、有路燈、有雙向車道。這條什麼都沒有。一邊是山，一邊是溝。如果出了事——", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他沒有讓自己想完這句話。他握緊了器材箱的把手，把自己往車廂更裡面的角落縮了縮。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車燈照到了前面。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)什麼——", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "先是光——車燈打在某個東西上，反射回來，金屬的反光。然後輪廓出現了。一輛車。停在路邊。橘色的。車頂上有閃燈，沒開。維修工程車。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "在維修車後面，是一排東西。黃黑相間的塑膠路障。至少四個。排成一道弧線，把右半邊的車道完全封死。路障後面散落著幾根被風折斷的樹枝，橫七豎八地躺在路面上。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "在路障和工程車之間——站著一個人。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黑色雨衣。帽沿壓得很低。整個人被雨衣裹得嚴嚴實實，看不出身形。那個人站在路中央，面朝駕駛座的方向，舉起了右手——手心朝外，五指張開。停車的手勢。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)黑雨衣。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)在這裡。在這種路上。在雨裡。攔車。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Driver, character: "司機", dialogue: "靠——！", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "煞車聲。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "輪胎在濕滑路面上尖叫，那聲音刺耳得讓人牙齒發酸。顧言的身體被慣性猛地往前甩，膝蓋撞上硬碟箱，胸口撞上攝影腳架的支架，疼痛讓他的視線瞬間白了一下。車在打滑。他能感覺到——車尾向右甩，車頭向左偏，整台車像一條被拽住尾巴的魚，在路面上橫過來。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "金屬撞擊的聲音。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "右前方。車頭擦上了護欄。護欄的鐵管在撞擊下凹陷、扭曲，發出一聲讓牙齒發酸的、長長的金屬呻吟。車身被彈開，然後——重心消失了。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)翻——", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "世界翻了。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "不是慢慢傾斜。是突然的、整個翻過去。車體離開了路面，越過被撞斷的護欄，向右傾倒。顧言感覺到自己的身體離開了地面——沒有安全帶，他什麼都沒有——他和器材箱、硬碟盒、攝影腳架一起，像被裝進一個搖晃的盒子裡的碎片，全部往一個方向砸過去。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "砸。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "器材箱砸在他的胸口。攝影腳架砸在他的肩膀。一個硬殼箱的角撞上了他的太陽穴。疼痛不是一下一下的——是同時的、疊加的、像全身的痛一下子全炸開了。他的嘴張開了，但什麼聲音都沒發出來。空氣被從肺裡擠出去了。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後是翻滾。一次。兩次。每一次翻滾，車廂裡的東西都在重新排列，砸在他身上不同的位置。他用雙手抱住頭，蜷成一團，但器材箱壓在他的胸口和腹部，他動不了。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "撞擊。最後一次。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車停了。停在一個傾斜的角度——車底朝向山坡，車頂朝向排水溝。歪的。顧言被卡在器材箱和車廂壁之間，整個人像被折疊了一樣。他的胸口壓著兩個器材箱，重量讓他每一次呼吸都只能吸進半口氣。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)活著。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)還活著。胸口。壓著。喘不上來。手指——還能動。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "雨聲。從外面灌進來的。車窗碎了——不知道什麼時候碎的——雨水從裂縫裡斜斜地打進來，澆在他的臉上、脖子上。他的眼睛睜著，但只能看到模糊的、晃動的、深淺不一的黑色。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "駕駛座那邊沒有聲音。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)司機。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)叫不出來。喉嚨裡有聲音，胸口壓著，發不出來。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他不知道過了多久。也許一分鐘。也許五分鐘。意識像一盞快沒電的燈，明一下，暗一下。每次暗下去的時候，雨聲就變得非常非常遠。每次亮起來的時候，胸口的疼痛就重新灌回來。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後他聽到了聲音。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "腳步聲。踩在碎石和積水裡的。不急。從車外面傳過來。嘎吱。嘎吱。嘎吱。越來越近。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後是一個金屬的聲音——車門。後車廂的門。有人在外面拉它。變形的門框發出刺耳的金屬摩擦聲，然後——吱呀——被拉開了一條縫。大約三十公分。雨水從縫隙裡斜斜地灌進來，混著一絲從外面透進來的、灰濛濛的天光。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)有人。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)來了。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一隻手從縫隙裡伸了進來。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "戴著手套。黑色的，橡膠的，雨天才會戴的那種工作手套。手套的表面沾著水珠，在灰光裡反著光。那隻手沒有猶豫——它直接越過了顧言的臉、越過了他被壓住的胸口、伸向了車廂的更深處。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯沒有看我。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那隻手沒有碰他。沒有檢查他還活著沒有。沒有喊「有人嗎」。它直接越過了他，像他不存在一樣，精準地、目的明確地伸向了車廂深處的一個位置。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黑色相機包。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "那個他在出發前才發現的、貼著「攝影組備份」標籤的黑色硬殼相機包。手套的手指扣住了包的提手，用力一拽。包被器材箱卡住了。手停頓了一下，調整了角度，再拽——包從縫隙裡被拖了出去。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "拉鏈的聲音。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "從外面傳來的。拉鏈被拉開的聲音。然後是翻找的聲音——手指在布料和塑膠配件之間摸索的、窸窸窣窣的聲音。持續了大約八秒。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "然後那個聲音停了。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "一個低沉的、被雨聲蓋住大半的聲音從車門縫隙外面傳進來——成年人的聲音，男的，語調平平的。像在陳述一個已經確認過的事實。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.BlackRaincoat, character: "黑雨衣", dialogue: "不是這個。東西沒出來。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.BlackRaincoat_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)什麼。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)「不是這個。東西沒出來。」", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他在找東西。在相機包裡找。相機包是空的——他翻完了——裡面沒有他要的東西。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他要的是什麼？", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)相機。他在找相機。訊息裡說的「相機」。上一輪鐘樓上那個人問的「相機在哪裡」。現在這個人在這台車上找的，是同一樣東西。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)相機不在這裡。包是空的。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他們不是在找我。他們不知道我在這台車上。他們要的是那個包。他們要的是——東西。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他想叫。他想喊「救命」。想喊「我在這裡」。但器材箱壓在他的胸口，每一次他試圖發聲，肺裡的空氣都不夠撐起一個完整的音節。從喉嚨裡擠出來的，只有氣音。一團潮濕的、破碎的、誰也聽不見的氣音。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)叫不出來。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車體動了一下。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "很小的位移。但他在車裡感覺到了——重心在變。傾斜的角度在加大。雨水從碎裂的車窗裡灌得更多了。他腳下的器材箱開始緩慢地、一公分一公分地往下滑。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)在滑。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)車在往溝裡滑。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "外面那個人似乎聽到了什麼。翻找的聲音停了。腳步聲響了一下——很短，像一個轉身的動作。透過車門的縫隙，顧言看到了一個模糊的輪廓——黑色雨衣的背影，在雨幕裡朝這邊轉過來了半個身體。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)他聽到了。他知道車在動——", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "但雨太大了。水從天上砸下來的聲音蓋住了一切。那個輪廓在雨幕裡停了大約兩秒。然後——它沒有靠近。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "車又滑了。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "這一次不是緩慢的。是斷裂。護欄殘存的固定點鬆脫了——或者排水溝邊緣的泥土被雨水泡軟了、塌了——車體猛地向下墜了一截。顧言的身體跟著車一起墜，然後器材箱也跟著砸下來，壓在他的胸口上，把最後一點空氣全部擠了出去。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "疼痛超過了某個臨界點。然後疼痛本身開始變遠。像有人把音量旋鈕往左擰，所有的感覺——痛、冷、濕、恐懼——都在變小、變遠、變成背景裡的雜訊。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)⋯⋯", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不是鐘樓。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)上一輪，我死在鐘樓。22:22。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)現在——還沒到晚上。天還亮著。不到六點半。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Scared },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)提前了。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Shocked },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)死。提前了。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "他的視野在收窄。邊緣先黑，然後向中心蔓延，像墨水在宣紙上擴散。最後剩下的那一小塊光——是車門縫隙裡透進來的、灰濛濛的、被雨水淋透的天光——也在縮小。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)灰色膠帶。臨時路障。改道電話。空的相機包。「東西沒出來」。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不是意外。", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Base },
    { characterId: CharacterId.GuYan, character: "顧言", dialogue: "(內心)不是意外——", background: Background.Chapter_2_Ch2_Act11_S0, portrait: Portrait.GuYan_Trembling },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "最後那一塊光滅了。", background: Background.Chapter_2_Ch2_Act11_S0 },
    { characterId: CharacterId.Narrator, character: "旁白", dialogue: "黑。", background: Background.Chapter_2_Ch2_Act11_S0 },
];
